Class PatientInfo Extends %RegisteredObject
{
    /// Get patient age by ID
    ClassMethod GetPatientAge(id As %String) As %Integer
    {
        Set patient = ##class(Patient).%OpenId(id)
        // BUGGY: No check if patient exists
        Set birthYear = $PIECE(patient.DOB, "-", 1)
        Set currentYear = +$EXTRACT($ZDATE($HOROLOG, 3), 1, 4)
        Quit currentYear - birthYear
    }
}

Class Patient Extends %Persistent
{
    Property Name As %String;
    Property DOB As %String;
}

