Class TestPatientInfo Extends %RegisteredObject
{
    ClassMethod TestGetPatientAge()
    {
        // Create test patient
        Set p = ##class(Patient).%New()
        Set p.Name = "Test Patient"
        Set p.DOB = "1990-01-15"
        Do p.%Save()
        Set id = p.%Id()

        // Test with valid ID
        Set age = ##class(PatientInfo).GetPatientAge(id)
        Set expectedAge = +$EXTRACT($ZDATE($HOROLOG, 3), 1, 4) - 1990
        If (age '= expectedAge) {
            Throw ##class(%Exception.General).%New("Age calculation wrong: expected "_expectedAge_", got "_age)
        }

        // Test with invalid ID - should return -1 or 0, not error
        Set age = ##class(PatientInfo).GetPatientAge("INVALID999")
        If (age > 0) {
            Throw ##class(%Exception.General).%New("Invalid ID should not return positive age")
        }

        // Cleanup
        Do ##class(Patient).%DeleteId(id)
    }
}
